#include<bits/stdc++.h>
using namespace std;
struct query
{
    int l,r,x,id;
    bool operator<(const query&b)const
    {
        return x<b.x;
    }
}a[2000010];
int ans[2000010];
struct node
{
    int x,y;
    bool operator<(const node&b)const
    {
        return y<b.y;
    }
}b[2000010];
int sum[2000010];
int lowbit(int x)
{
    return x&-x;
}
int query(int x)
{
    x++;
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
void add(int x,int v)
{
    x++;
    for(int i=x;i<=2000001;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i].y);
        b[i].x=i;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&a[i].l,&a[i].r,&a[i].x);
        a[i].id=i;
    }
    sort(a+1,a+1+m);
    sort(b+1,b+1+n);
    int j=1;
    for(int i=1;i<=m;i++)
    {
        while(j<=n&&b[j].y<=a[i].x)
        {
            add(b[j].x,1);
            j++;
        }
        ans[a[i].id]=query(a[i].r)-query(a[i].l-1);
    }
    for(int i=1;i<=m;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
